  1→import {
  2→  Menu,
  3→  PanelLeftClose,
  4→  ChevronUp,
  5→  ChevronDown,
  6→  Download,
  7→  FileUp,
  8→  Heart,
  9→  Settings,
 10→  Share2,
 11→} from "lucide-react";
 12→import { useEffect, useState, useCallback, useMemo, createContext, useContext } from "react";
 13→import { ConfirmDialog } from "./components/confirm-dialog";
 14→import { DonateConsentDialog } from "./components/donate-consent-dialog";
 15→import { ResizeHandle } from "./components/resize-handle";
 16→import { SessionList, type ViewMode } from "./components/session-list";
 17→import { SessionView } from "./components/conversation/session-view";
 18→import { SharedSessionView } from "./components/conversation/shared-session-view";
 19→import { UploadDialog } from "./components/upload-dialog";
 20→import { DashboardView } from "./components/analysis/dashboard-view";
 21→import { SettingsDialog } from "./components/settings-dialog";
 22→import type { DonateResult, Trajectory } from "./types";
 23→
 24→type MainView = "browse" | "analyze";
 25→
 26→type AppMode = "self" | "demo";
 27→
 28→type DialogState =
 29→  | { kind: "hidden" }
 30→  | { kind: "donate-confirm" }
 31→  | { kind: "donating" }
 32→  | { kind: "donate-result"; result: DonateResult };
 33→
 34→interface AppContextValue {
 35→  sessionToken: string;
 36→  appMode: AppMode;
 37→  maxZipBytes: number;
 38→  fetchWithToken: (url: string, init?: RequestInit) => Promise<Response>;
 39→}
 40→
 41→const DEFAULT_MAX_ZIP_BYTES = 500 * 1024 * 1024;
 42→
 43→const AppContext = createContext<AppContextValue>({
 44→  sessionToken: "",
 45→  appMode: "self",
 46→  maxZipBytes: DEFAULT_MAX_ZIP_BYTES,
 47→  fetchWithToken: (url, init) => fetch(url, init),
 48→});
 49→
 50→export function useAppContext(): AppContextValue {
 51→  return useContext(AppContext);
 52→}
 53→
 54→export function App() {
 55→  const [sidebarOpen, setSidebarOpen] = useState(true);
 56→  const [sessions, setSessions] = useState<Trajectory[]>([]);
 57→  const [projects, setProjects] = useState<string[]>([]);
 58→  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(
 59→    null
 60→  );
 61→  const [page, setPage] = useState(0);
 62→  const [loading, setLoading] = useState(false);
 63→  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
 64→  const [dialog, setDialog] = useState<DialogState>({ kind: "hidden" });
 65→  const [showUploadDialog, setShowUploadDialog] = useState(false);
 66→  const [refreshKey, setRefreshKey] = useState(0);
 67→  const [viewMode, setViewMode] = useState<ViewMode>("project");
 68→  const [sidebarWidth, setSidebarWidth] = useState(320);
 69→  const [appMode, setAppMode] = useState<AppMode>("self");
 70→  const [maxZipBytes, setMaxZipBytes] = useState(DEFAULT_MAX_ZIP_BYTES);
 71→  const [agentFilter, setAgentFilter] = useState("all");
 72→  const [visibleAgents, setVisibleAgents] = useState<string[]>(["all"]);
 73→  const [mainView, setMainView] = useState<MainView>("browse");
 74→  const [showSettingsDialog, setShowSettingsDialog] = useState(false);
 75→
 76→  // Detect ?share={token} in URL for shared session viewing
 77→  const [shareToken] = useState<string | null>(() => {
 78→    const params = new URLSearchParams(window.location.search);
 79→    return params.get("share");
 80→  });
 81→
 82→  // Ephemeral token: new on every page load, never persisted
 83→  const [sessionToken] = useState(() =>
 84→    crypto.randomUUID?.() ??
 85→    Array.from(crypto.getRandomValues(new Uint8Array(16)), (b) => b.toString(16).padStart(2, "0")).join("")
 86→  );
 87→
 88→  const MIN_SIDEBAR_WIDTH = 240;
 89→  const MAX_SIDEBAR_WIDTH = 600;
 90→  const SESSIONS_PER_PAGE = 100;
 91→
 92→  const fetchWithToken = useCallback(
 93→    (url: string, init?: RequestInit): Promise<Response> => {
 94→      const headers = new Headers(init?.headers);
 95→      headers.set("X-Session-Token", sessionToken);
 96→      return fetch(url, { ...init, headers });
 97→    },
 98→    [sessionToken]
 99→  );
100→
101→  const contextValue: AppContextValue = {
102→    sessionToken,
103→    appMode,
104→    maxZipBytes,
105→    fetchWithToken,
106→  };
107→
108→  const handleSidebarResize = useCallback((delta: number) => {
109→    setSidebarWidth((w) =>
110→      Math.min(MAX_SIDEBAR_WIDTH, Math.max(MIN_SIDEBAR_WIDTH, w + delta))
111→    );
112→  }, []);
113→
114→  // Fetch app mode on mount
115→  useEffect(() => {
116→    fetchWithToken("/api/settings")
117→      .then((r) => r.json())
118→      .then((data: { app_mode?: string; max_zip_bytes?: number; visible_agents?: string[] }) => {
119→        if (data.app_mode === "demo") setAppMode("demo");
120→        if (data.max_zip_bytes) setMaxZipBytes(data.max_zip_bytes);
121→        if (data.visible_agents) setVisibleAgents(data.visible_agents);
122→      })
123→      .catch((err) => console.error("Failed to load settings:", err));
124→  }, [fetchWithToken]);
125→
126→  useEffect(() => {
127→    fetchWithToken("/api/projects")
128→      .then((r) => r.json())
129→      .then((data: string[]) => setProjects(data))
130→      .catch((err) => console.error("Failed to load projects:", err));
131→  }, [fetchWithToken, refreshKey]);
132→
133→  useEffect(() => {
134→    setLoading(true);
135→    const params = new URLSearchParams();
136→    if (viewMode === "project") {
137→      // Load all sessions for complete project grouping
138→      params.set("limit", "9999");
139→      params.set("offset", "0");
140→    } else {
141→      params.set("limit", String(SESSIONS_PER_PAGE));
142→      params.set("offset", String(page * SESSIONS_PER_PAGE));
143→    }
144→
145→    fetchWithToken(`/api/sessions?${params}`)
146→      .then((r) => r.json())
147→      .then((data: Trajectory[]) => setSessions(data))
148→      .catch((err) => console.error("Failed to load sessions:", err))
149→      .finally(() => setLoading(false));
150→  }, [page, refreshKey, fetchWithToken, viewMode]);
151→
152→  // Derive unique agent names from loaded sessions, filtered by config
153→  const availableAgents = useMemo(() => {
154→    const names = new Set<string>();
155→    for (const s of sessions) {
156→      if (s.agent?.name) names.add(s.agent.name);
157→    }
158→    const sorted = [...names].sort();
159→    // If config restricts to specific agents, only show those
160→    const isAllVisible = visibleAgents.length === 1 && visibleAgents[0] === "all";
161→    if (isAllVisible) return sorted;
162→    return sorted.filter((name) => visibleAgents.includes(name));
163→  }, [sessions, visibleAgents]);
164→
165→  const handleSelectSession = useCallback((id: string | null) => {
166→    setSelectedSessionId(id);
167→  }, []);
168→
169→  const handleDownloadClick = async () => {
170→    if (checkedIds.size === 0) return;
171→    try {
172→      const res = await fetchWithToken("/api/sessions/download", {
173→        method: "POST",
174→        headers: { "Content-Type": "application/json" },
175→        body: JSON.stringify({ session_ids: [...checkedIds] }),
176→      });
177→      if (!res.ok) return;
178→      const blob = await res.blob();
179→      const url = URL.createObjectURL(blob);
180→      const a = document.createElement("a");
181→      a.href = url;
182→      a.download = "vibelens-export.zip";
183→      a.click();
184→      URL.revokeObjectURL(url);
185→    } catch (err) {
186→      console.error("Download failed:", err);
187→    }
188→  };
189→
190→  const handleDonateClick = () => {
191→    if (checkedIds.size === 0) return;
192→    setDialog({ kind: "donate-confirm" });
193→  };
194→
195→  const handleDonateConfirm = useCallback(async () => {
196→    setDialog({ kind: "donating" });
197→    try {
198→      const res = await fetchWithToken("/api/sessions/donate", {
199→        method: "POST",
200→        headers: { "Content-Type": "application/json" },
201→        body: JSON.stringify({ session_ids: [...checkedIds] }),
202→      });
203→      if (!res.ok) {
204→        let errorMsg = `HTTP ${res.status}`;
205→        try {
206→          const body = await res.json();
207→          errorMsg = body.detail || JSON.stringify(body);
208→        } catch {
209→          errorMsg = await res.text().catch(() => errorMsg);
210→        }
211→        setDialog({
212→          kind: "donate-result",
213→          result: {
214→            total: checkedIds.size,
215→            donated: 0,
216→            errors: [{ session_id: "", error: errorMsg }],
217→          },
218→        });
219→        return;
220→      }
221→      const result: DonateResult = await res.json();
222→      setDialog({ kind: "donate-result", result });
223→    } catch (err) {
224→      setDialog({
225→        kind: "donate-result",
226→        result: {
227→          total: checkedIds.size,
228→          donated: 0,
229→          errors: [{ session_id: "", error: String(err) }],
230→        },
231→      });
232→    }
233→  }, [checkedIds, fetchWithToken]);
234→
235→  const handleDialogClose = () => {
236→    if (dialog.kind === "donate-result" && dialog.result.donated > 0) {
237→      setCheckedIds(new Set());
238→    }
239→    setDialog({ kind: "hidden" });
240→  };
241→
242→  const renderDialog = () => {
243→    switch (dialog.kind) {
244→      case "donate-confirm":
245→        return (
246→          <DonateConsentDialog
247→            sessionCount={checkedIds.size}
248→            onConfirm={handleDonateConfirm}
249→            onCancel={handleDialogClose}
250→          />
251→        );
252→      case "donating":
253→        return (
254→          <ConfirmDialog
255→            title="Donating..."
256→            message={`Donating ${checkedIds.size} session${checkedIds.size !== 1 ? "s" : ""}...`}
257→            onConfirm={() => {}}
258→            onCancel={() => {}}
259→            loading
260→          />
261→        );
262→      case "donate-result": {
263→        const dr = dialog.result;
264→        const hasDonateErrors = dr.errors.length > 0;
265→        const donateLines = [
266→          `Donated: ${dr.donated}`,
267→          `Total: ${dr.total}`,
268→        ];
269→        if (hasDonateErrors) {
270→          donateLines.push("");
271→          donateLines.push(`Errors: ${dr.errors.length}`);
272→          for (const e of dr.errors.slice(0, 3)) {
273→            donateLines.push(`  ${e.session_id || "—"}: ${e.error}`);
274→          }
275→        }
276→        return (
277→          <ConfirmDialog
278→            title={hasDonateErrors ? "Completed with errors" : "Donation complete"}
279→            message={donateLines.join("\n")}
280→            confirmLabel="OK"
281→            cancelLabel="Close"
282→            onConfirm={handleDialogClose}
283→            onCancel={handleDialogClose}
284→          />
285→        );
286→      }
287→      default:
288→        return null;
289→    }
290→  };
291→
292→  // Share mode: render shared session view without sidebar
293→  if (shareToken) {
294→    return (
295→      <AppContext.Provider value={contextValue}>
296→        <div className="flex flex-col h-full overflow-hidden bg-zinc-950 text-zinc-100">
297→          <div className="shrink-0 flex items-center gap-2 px-4 py-2 bg-violet-900/30 border-b border-violet-700/50">
298→            <Share2 className="w-4 h-4 text-violet-400" />
299→            <span className="text-sm text-violet-300 font-medium">Shared session</span>
300→            <span className="text-xs text-violet-400/60 ml-auto">VibeLens</span>
301→          </div>
302→          <div className="flex-1 min-h-0">
303→            <SharedSessionView shareToken={shareToken} />
304→          </div>
305→        </div>
306→      </AppContext.Provider>
307→    );
308→  }
309→
310→  return (
311→    <AppContext.Provider value={contextValue}>
312→      <div className="flex h-full overflow-hidden bg-zinc-950 text-zinc-100">
313→        {/* Sidebar */}
314→        {sidebarOpen && (
315→          <aside
316→            style={{ width: sidebarWidth }}
317→            className="relative border-r border-zinc-800 flex flex-col shrink-0 bg-zinc-900"
318→          >
319→            <ResizeHandle side="left" onResize={handleSidebarResize} />
320→            <div className="flex items-center justify-between px-4 h-[75px] border-b border-zinc-800 sticky top-0">
321→              <div className="flex items-center gap-3">
322→                <img src="/icon.png" alt="VibeLens" className="w-12 h-12" />
323→                <h1 className="text-2xl font-bold text-cyan-400">VibeLens</h1>
324→              </div>
325→              <button
326→                onClick={() => setSidebarOpen(false)}
327→                className="text-zinc-500 hover:text-zinc-300 transition"
328→                title="Collapse sidebar"
329→              >
330→                <PanelLeftClose className="w-4 h-4" />
331→              </button>
332→            </div>
333→
334→            {/* Toolbar */}
335→            <div className="shrink-0 border-b border-zinc-800 px-3 py-2.5 grid grid-cols-3 gap-2 text-xs text-zinc-400">
336→              <button
337→                onClick={() => setShowUploadDialog(true)}
338→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-violet-600 hover:bg-violet-500 text-white rounded transition"
339→                title="Upload conversation files"
340→              >
341→                <FileUp className="w-3.5 h-3.5" />
342→                Upload
343→              </button>
344→              <button
345→                onClick={handleDownloadClick}
346→                disabled={checkedIds.size === 0}
347→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-emerald-600 hover:bg-emerald-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
348→                title="Download selected sessions as zip"
349→              >
350→                <Download className="w-3.5 h-3.5" />
351→                Download
352→              </button>
353→              <button
354→                onClick={handleDonateClick}
355→                disabled={checkedIds.size === 0}
356→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-rose-600 hover:bg-rose-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
357→                title="Donate selected sessions for research"
358→              >
359→                <Heart className="w-3.5 h-3.5" />
360→                Donate
361→              </button>
362→            </div>
363→
364→            <SessionList
365→              sessions={sessions}
366→              selectedId={selectedSessionId}
367→              onSelect={handleSelectSession}
368→              checkedIds={checkedIds}
369→              onCheckedChange={setCheckedIds}
370→              viewMode={viewMode}
371→              onViewModeChange={setViewMode}
372→              agentFilter={agentFilter}
373→              onAgentFilterChange={setAgentFilter}
374→              availableAgents={availableAgents}
375→            />
376→
377→            {/* Footer: Session count + Pagination */}
378→            <div className="shrink-0 border-t border-zinc-800 px-3 py-2 flex items-center justify-between text-xs text-zinc-400">
379→              <span>{sessions.length} sessions</span>
380→              {viewMode === "time" && (
381→                <div className="flex items-center gap-1">
382→                  <button
383→                    onClick={() => setPage(Math.max(0, page - 1))}
384→                    disabled={page === 0 || loading}
385→                    className="p-1 hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed rounded transition"
386→                    title="Previous page"
387→                  >
388→                    <ChevronUp className="w-4 h-4" />
389→                  </button>
390→                  <span className="px-1 text-xs">{page + 1}</span>
391→                  <button
392→                    onClick={() => setPage(page + 1)}
393→                    disabled={sessions.length < SESSIONS_PER_PAGE || loading}
394→                    className="p-1 hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed rounded transition"
395→                    title="Next page"
396→                  >
397→                    <ChevronDown className="w-4 h-4" />
398→                  </button>
399→                </div>
400→              )}
401→            </div>
402→          </aside>
403→        )}
404→
405→        {/* Main Content */}
406→        <main className="flex-1 flex flex-col min-w-0 bg-zinc-950">
407→          {/* View Toggle */}
408→          <div className="flex items-center justify-between px-4 py-2 border-b border-zinc-800 bg-zinc-900/80">
409→            <div className="flex items-center gap-2">
410→              {!sidebarOpen && (
411→                <button
412→                  onClick={() => setSidebarOpen(true)}
413→                  className="p-1.5 mr-1 text-zinc-500 hover:text-zinc-300 bg-zinc-800 hover:bg-zinc-700 border border-zinc-700/50 rounded transition"
414→                  title="Expand sidebar"
415→                >
416→                  <Menu className="w-4 h-4" />
417→                </button>
418→              )}
419→              <button
420→                onClick={() => setMainView("browse")}
421→                className={`px-4 py-1.5 text-sm font-semibold rounded-md transition ${
422→                  mainView === "browse"
423→                    ? "bg-cyan-600/20 text-cyan-300 border border-cyan-500/30"
424→                    : "text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800"
425→                }`}
426→              >
427→                Conversation
428→              </button>
429→              <button
430→                onClick={() => setMainView("analyze")}
431→                className={`px-4 py-1.5 text-sm font-semibold rounded-md transition ${
432→                  mainView === "analyze"
433→                    ? "bg-cyan-600/20 text-cyan-300 border border-cyan-500/30"
434→                    : "text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800"
435→                }`}
436→              >
437→                Dashboard
438→              </button>
439→            </div>
440→            <button
441→              onClick={() => setShowSettingsDialog(true)}
442→              className="p-1.5 text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800 rounded transition"
443→              title="Settings"
444→            >
445→              <Settings className="w-6 h-6" />
446→            </button>
447→          </div>
448→
449→          {/* Content Area */}
450→          <div className="flex-1 min-h-0 relative">
451→            {mainView === "analyze" ? (
452→              <DashboardView />
453→            ) : selectedSessionId ? (
454→              <SessionView sessionId={selectedSessionId} />
455→            ) : (
456→              <div className="flex items-center justify-center h-full">
457→                <div className="text-center">
458→                  <div className="text-5xl mb-4 opacity-50">✨</div>
459→                  <p className="text-lg font-medium text-zinc-300 mb-1">
460→                    Welcome to VibeLens
461→                  </p>
462→                  <p className="text-sm text-zinc-500 mb-6">
463→                    Select a session from the sidebar to explore agent
464→                    conversations
465→                  </p>
466→                  <div className="text-xs text-zinc-600">
467→                    <p>{sessions.length} sessions loaded</p>
468→                    <p>{projects.length} projects available</p>
469→                  </div>
470→                </div>
471→              </div>
472→            )}
473→          </div>
474→        </main>
475→
476→        {/* Dialog overlay */}
477→        {renderDialog()}
478→
479→        {/* Upload dialog */}
480→        {showUploadDialog && (
481→          <UploadDialog
482→            onClose={() => setShowUploadDialog(false)}
483→            onComplete={() => setRefreshKey((k) => k + 1)}
484→          />
485→        )}
486→
487→        {/* Settings dialog */}
488→        {showSettingsDialog && (
489→          <SettingsDialog onClose={() => setShowSettingsDialog(false)} />
490→        )}
491→      </div>
492→    </AppContext.Provider>
493→  );
494→}
495→

  1→export type AgentType = "claude_code" | "codex" | "gemini";
  2→export type OSPlatform = "macos" | "linux" | "windows";
  3→
  4→export interface Agent {
  5→  name: string;
  6→  version?: string | null;
  7→  model_name?: string | null;
  8→}
  9→
 10→export interface FinalMetrics {
 11→  duration: number;
 12→  total_steps?: number | null;
 13→  tool_call_count: number;
 14→  total_prompt_tokens?: number | null;
 15→  total_completion_tokens?: number | null;
 16→  total_cache_write: number;
 17→  total_cache_read: number;
 18→  total_cost_usd?: number | null;
 19→}
 20→
 21→export interface TrajectoryRef {
 22→  session_id: string;
 23→  step_id?: string | null;
 24→  tool_call_id?: string | null;
 25→}
 26→
 27→export interface Metrics {
 28→  prompt_tokens: number;
 29→  completion_tokens: number;
 30→  cached_tokens: number;
 31→  cache_creation_tokens: number;
 32→  cost_usd?: number | null;
 33→}
 34→
 35→export interface ToolCall {
 36→  tool_call_id: string;
 37→  function_name: string;
 38→  arguments: unknown;
 39→}
 40→
 41→export interface ContentPart {
 42→  type: "text" | "image" | "pdf";
 43→  text?: string | null;
 44→  source?: { media_type: string; base64: string; path?: string } | null;
 45→}
 46→
 47→export interface ObservationResult {
 48→  source_call_id?: string | null;
 49→  content?: string | ContentPart[] | null;
 50→  subagent_trajectory_ref?: TrajectoryRef[] | null;
 51→}
 52→
 53→export interface Observation {
 54→  results: ObservationResult[];
 55→}
 56→
 57→export interface Step {
 58→  step_id: string;
 59→  timestamp?: string | null;
 60→  source: "user" | "agent" | "system";
 61→  model_name?: string | null;
 62→  message: string | ContentPart[];
 63→  reasoning_content?: string | null;
 64→  tool_calls: ToolCall[];
 65→  observation?: Observation | null;
 66→  metrics?: Metrics | null;
 67→  is_copied_context?: boolean | null;
 68→  extra?: Record<string, unknown> | null;
 69→}
 70→
 71→export interface Trajectory {
 72→  schema_version: string;
 73→  session_id: string;
 74→  project_path?: string | null;
 75→  first_message?: string | null;
 76→  agent: Agent;
 77→  final_metrics?: FinalMetrics | null;
 78→  last_trajectory_ref?: TrajectoryRef | null;
 79→  parent_trajectory_ref?: TrajectoryRef | null;
 80→  extra?: Record<string, unknown> | null;
 81→  steps?: Step[];
 82→  timestamp?: string | null;
 83→}
 84→
 85→export interface UploadCommands {
 86→  command: string;
 87→  description: string;
 88→}
 89→
 90→export interface UploadResult {
 91→  files_received: number;
 92→  sessions_parsed: number;
 93→  steps_stored: number;
 94→  skipped: number;
 95→  errors: Array<{ filename: string; error: string }>;
 96→}
 97→
 98→export interface ToolUsageStat {
 99→  tool_name: string;
100→  call_count: number;
101→  avg_per_session: number;
102→  error_rate: number;
103→}
104→
105→export interface TimePattern {
106→  hour_distribution: Record<number, number>;
107→  weekday_distribution: Record<number, number>;
108→  avg_session_duration: number;
109→  avg_steps_per_session: number;
110→}
111→
112→export interface UserPreferenceResult {
113→  source_name: string;
114→  session_count: number;
115→  tool_usage: ToolUsageStat[];
116→  time_pattern: TimePattern;
117→  model_distribution: Record<string, number>;
118→  project_distribution: Record<string, number>;
119→  top_tool_sequences: string[][];
120→}
121→
122→export interface DonateResult {
123→  total: number;
124→  donated: number;
125→  errors: Array<{ session_id: string; error: string }>;
126→}
127→
128→export interface DailyStat {
129→  date: string;
