  1→import {
  2→  Loader2,
  3→  Download,
  4→  Share2,
  5→  Check,
  6→  BarChart3,
  7→  Bot,
  8→  Clock,
  9→  MessageSquare,
 10→  Wrench,
 11→  FolderOpen,
 12→  Cpu,
 13→  Calendar,
 14→  Hash,
 15→  Layers,
 16→  Zap,
 17→} from "lucide-react";
 18→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
 19→import { useAppContext } from "../../app";
 20→import type { Step, Trajectory } from "../../types";
 21→import { StepBlock } from "./message-block";
 22→import { SubAgentBlock } from "./sub-agent-block";
 23→import { StepTimeline } from "./step-timeline";
 24→import { PromptNavPanel } from "./prompt-nav-panel";
 25→import { formatTokens, formatDuration, formatCost, extractUserText, baseProjectName } from "../../utils";
 26→
 27→interface SessionViewProps {
 28→  sessionId: string;
 29→  sharedTrajectories?: Trajectory[];
 30→}
 31→
 32→export function SessionView({ sessionId, sharedTrajectories }: SessionViewProps) {
 33→  const { fetchWithToken } = useAppContext();
 34→  const [trajectories, setTrajectories] = useState<Trajectory[]>([]);
 35→  const [loading, setLoading] = useState(true);
 36→  const [error, setError] = useState("");
 37→  const [activeStepId, setActiveStepId] = useState<string | null>(null);
 38→  const [promptNavWidth, setPromptNavWidth] = useState(224);
 39→  const [sessionCost, setSessionCost] = useState<number | null>(null);
 40→  const [shareStatus, setShareStatus] = useState<"idle" | "sharing" | "copied">("idle");
 41→  const stepsRef = useRef<HTMLDivElement>(null);
 42→  const isNavigatingRef = useRef(false);
 43→  const isSharedView = !!sharedTrajectories;
 44→
 45→  const MIN_PROMPT_NAV_WIDTH = 160;
 46→  const MAX_PROMPT_NAV_WIDTH = 400;
 47→
 48→  const handlePromptNavResize = useCallback((delta: number) => {
 49→    setPromptNavWidth((w) =>
 50→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 51→    );
 52→  }, []);
 53→
 54→  useEffect(() => {
 55→    setActiveStepId(null);
 56→    setSessionCost(null);
 57→
 58→    // When rendering shared data, skip the API fetch
 59→    if (sharedTrajectories) {
 60→      setTrajectories(sharedTrajectories);
 61→      setLoading(false);
 62→      return;
 63→    }
 64→
 65→    setLoading(true);
 66→    setError("");
 67→    setTrajectories([]);
 68→
 69→    fetchWithToken(`/api/sessions/${sessionId}`)
 70→      .then((res) => {
 71→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 72→        return res.json();
 73→      })
 74→      .then((data: Trajectory[]) => {
 75→        setTrajectories(data);
 76→      })
 77→      .catch((err: Error) => setError(err.message))
 78→      .finally(() => setLoading(false));
 79→  }, [sessionId, fetchWithToken, sharedTrajectories]);
 80→
 81→  // Fetch session analytics for cost estimation (non-blocking, skip for shared views)
 82→  useEffect(() => {
 83→    if (!sessionId || loading || isSharedView) return;
 84→    fetchWithToken(`/api/analysis/sessions/${sessionId}/stats`)
 85→      .then((res) => (res.ok ? res.json() : null))
 86→      .then((data) => {
 87→        if (data?.cost_usd != null) setSessionCost(data.cost_usd);
 88→      })
 89→      .catch(() => {});
 90→  }, [sessionId, loading, fetchWithToken]);
 91→
 92→  const main = useMemo(
 93→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
 94→    [trajectories]
 95→  );
 96→
 97→  const subAgents = useMemo(
 98→    () =>
 99→      trajectories
100→        .filter((t) => !!t.parent_trajectory_ref)
101→        .sort((a, b) => {
102→          const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
103→          const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
104→          return ta - tb;
105→        }),
106→    [trajectories]
107→  );
108→
109→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
110→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
111→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
112→  // chronologically correct position using timestamp heuristics.
113→  const subAgentsByStep = useMemo(() => {
114→    const map = new Map<string, Trajectory[]>();
115→    const orphans: Trajectory[] = [];
116→    const unlinked: Trajectory[] = [];
117→
118→    for (const sub of subAgents) {
119→      let placed = false;
120→      if (main?.steps) {
121→        for (const step of main.steps) {
122→          if (!step.observation) continue;
123→          for (const result of step.observation.results) {
124→            if (!result.subagent_trajectory_ref) continue;
125→            for (const ref of result.subagent_trajectory_ref) {
126→              if (ref.session_id === sub.session_id) {
127→                const existing = map.get(step.step_id) || [];
128→                existing.push(sub);
129→                map.set(step.step_id, existing);
130→                placed = true;
131→                break;
132→              }
133→            }
134→            if (placed) break;
135→          }
136→          if (placed) break;
137→        }
138→      }
139→      if (!placed) unlinked.push(sub);
140→    }
141→
142→    // Place unlinked sub-agents at the last main step whose timestamp
143→    // is <= the sub-agent's start timestamp. Falls back to orphans
144→    // only when no timestamp is available.
145→    for (const sub of unlinked) {
146→      const subTs = sub.timestamp ? new Date(sub.timestamp).getTime() : NaN;
147→      if (!isNaN(subTs) && main?.steps) {
148→        let bestStepId: string | null = null;
149→        for (const step of main.steps) {
150→          if (!step.timestamp) continue;
151→          const stepTs = new Date(step.timestamp).getTime();
152→          if (stepTs <= subTs) bestStepId = step.step_id;
153→          else break;
154→        }
155→        if (bestStepId) {
156→          const existing = map.get(bestStepId) || [];
157→          existing.push(sub);
158→          map.set(bestStepId, existing);
159→          continue;
160→        }
161→      }
162→      orphans.push(sub);
163→    }
164→
165→    return { map, orphans };
166→  }, [main, subAgents]);
167→
168→  const steps = (main?.steps || []) as Step[];
169→
170→  const userStepIds = useMemo(() => {
171→    return steps
172→      .filter((s) => s.source === "user" && extractUserText(s))
173→      .map((s) => s.step_id);
174→  }, [steps]);
175→
176→  // IntersectionObserver to track which user prompt is currently visible
177→  useEffect(() => {
178→    if (!stepsRef.current || userStepIds.length < 2) return;
179→
180→    const observer = new IntersectionObserver(
181→      (entries) => {
182→        if (isNavigatingRef.current) return;
183→        let topEntry: IntersectionObserverEntry | null = null;
184→        for (const entry of entries) {
185→          if (!entry.isIntersecting) continue;
186→          if (!topEntry || entry.boundingClientRect.top < topEntry.boundingClientRect.top) {
187→            topEntry = entry;
188→          }
189→        }
190→        if (topEntry) {
191→          setActiveStepId(topEntry.target.id.replace("step-", ""));
192→        }
193→      },
194→      {
195→        root: stepsRef.current,
196→        rootMargin: "-10% 0px -80% 0px",
197→        threshold: 0,
198→      }
199→    );
200→
201→    for (const stepId of userStepIds) {
202→      const el = document.getElementById(`step-${stepId}`);
203→      if (el) observer.observe(el);
204→    }
205→
206→    return () => observer.disconnect();
207→  }, [userStepIds]);
208→
209→  const SCROLL_SUPPRESS_MS = 800;
210→
211→  const handlePromptNavigate = useCallback((stepId: string) => {
212→    const el = document.getElementById(`step-${stepId}`);
213→    if (!el) return;
214→    isNavigatingRef.current = true;
215→    setActiveStepId(stepId);
216→    el.scrollIntoView({ behavior: "smooth", block: "start" });
217→    setTimeout(() => {
218→      isNavigatingRef.current = false;
219→    }, SCROLL_SUPPRESS_MS);
220→  }, []);
221→
222→  if (loading) {
223→    return (
224→      <div className="flex items-center justify-center h-full">
225→        <div className="text-center">
226→          <Loader2 className="w-8 h-8 text-cyan-500 animate-spin mx-auto mb-2" />
227→          <p className="text-sm text-zinc-400">Loading session...</p>
228→        </div>
229→      </div>
230→    );
231→  }
232→
233→  if (error) {
234→    return (
235→      <div className="flex items-center justify-center h-full p-4">
236→        <div className="text-center bg-rose-900/20 border border-rose-800 rounded-lg p-6 max-w-md">
237→          <p className="text-sm font-semibold text-rose-300 mb-2">Failed to load session</p>
238→          <p className="text-xs text-rose-400 mb-4 font-mono break-all">{error}</p>
239→          <button
240→            onClick={() => window.location.reload()}
241→            className="px-3 py-1 bg-rose-700/50 hover:bg-rose-700 rounded text-xs text-rose-200 transition"
242→          >
243→            Retry
244→          </button>
245→        </div>
246→      </div>
247→    );
248→  }
249→
250→  const handleShare = async () => {
251→    setShareStatus("sharing");
252→    try {
253→      const res = await fetchWithToken("/api/shares", {
254→        method: "POST",
255→        headers: { "Content-Type": "application/json" },
256→        body: JSON.stringify({ session_id: sessionId }),
257→      });
258→      if (!res.ok) throw new Error(`Failed to create share: ${res.status}`);
259→      const data = await res.json();
260→      await navigator.clipboard.writeText(data.url);
261→      setShareStatus("copied");
262→      setTimeout(() => setShareStatus("idle"), 2000);
263→    } catch (err) {
264→      console.error("Share failed:", err);
265→      setShareStatus("idle");
266→    }
267→  };
268→
269→  if (!main) return null;
270→
271→  const metrics = main.final_metrics;
272→  const promptCount = steps.filter(
273→    (s) => s.source === "user" && !s.extra?.is_skill_output && extractUserText(s)
274→  ).length;
275→  const skillCount = steps.filter(
276→    (s) => s.source === "user" && s.extra?.is_skill_output
277→  ).length;
278→  const totalTokens =
279→    (metrics?.total_prompt_tokens || 0) +
280→    (metrics?.total_completion_tokens || 0);
281→
282→  const isVisibleStep = (s: Step): boolean => {
283→    if (s.source === "user") {
284→      if (typeof s.message === "string") return !!s.message.trim();
285→      return s.message.length > 0;
286→    }
287→    return s.source === "agent" || s.source === "system";
288→  };
289→
290→  return (
291→    <div className="h-full flex flex-col overflow-hidden">
292→      {/* Session Header */}
293→      <div className="shrink-0 bg-zinc-900/95 border-b border-zinc-800 px-6 py-4">
294→        <div className="max-w-7xl mx-auto">
295→          {/* Row 1: Title + Meta Pills */}
296→          <div className="flex items-start justify-between mb-3">
297→            <div className="min-w-0 flex-1">
298→              <div className="flex items-center gap-2">
299→                <MetaPill
300→                  icon={<Hash className="w-3 h-3" />}
301→                  label={main.session_id.slice(0, 8)}
302→                  color="text-zinc-300"
303→                  tooltip={`Session ID: ${main.session_id}`}
304→                />
305→                <h2 className="text-sm font-semibold text-zinc-100 truncate">
306→                  {main.first_message || "Session"}
307→                </h2>
308→              </div>
309→              <div className="flex flex-wrap items-center gap-1.5 mt-2">
310→                {main.agent.model_name && (
311→                  <MetaPill
312→                    icon={<Cpu className="w-3 h-3" />}
313→                    label={`${main.agent.name}@${main.agent.model_name}`}
314→                    color="text-amber-300"
315→                    tooltip="Agent model used for this session"
316→                  />
317→                )}
318→                {main.timestamp && (
319→                  <MetaPill
320→                    icon={<Calendar className="w-3 h-3" />}
321→                    label={formatCreatedTime(main.timestamp)}
322→                    color="text-zinc-200"
323→                    tooltip="Session start time"
324→                  />
325→                )}
326→                {metrics && (
327→                  <MetaPill
328→                    icon={<Clock className="w-3 h-3" />}
329→                    label={formatDuration(metrics.duration)}
330→                    color="text-cyan-400"
331→                    tooltip="Total wall-clock duration of this session"
332→                  />
333→                )}
334→                <MetaPill
335→                  icon={<MessageSquare className="w-3 h-3" />}
336→                  label={`${promptCount} prompt${promptCount !== 1 ? "s" : ""}`}
337→                  color="text-blue-400"
338→                  tooltip="User prompts — messages typed by the human operator"
339→                />
340→                {skillCount > 0 && (
341→                  <MetaPill
342→                    icon={<Zap className="w-3 h-3" />}
343→                    label={`${skillCount} skill${skillCount !== 1 ? "s" : ""}`}
344→                    color="text-amber-300"
345→                    tooltip="Skill invocations — reusable prompts auto-injected by the agent"
346→                  />
347→                )}
348→                {metrics && (
349→                  <>
350→                    <MetaPill
351→                      icon={<Wrench className="w-3 h-3" />}
352→                      label={`${metrics.tool_call_count} tools`}
353→                      color="text-amber-400"
354→                      tooltip="Total tool calls made by the agent (Bash, Read, Edit, etc.)"
355→                    />
356→                    {metrics.total_steps && (
357→                      <MetaPill
358→                        icon={<Layers className="w-3 h-3" />}
359→                        label={`${metrics.total_steps} steps`}
360→                        color="text-zinc-200"
361→                        tooltip="Total conversation steps including user, agent, and system turns"
362→                      />
363→                    )}
364→                  </>
365→                )}
366→                {subAgents.length > 0 && (
367→                  <MetaPill
368→                    icon={<Bot className="w-3 h-3" />}
369→                    label={`${subAgents.length} sub-agent${subAgents.length !== 1 ? "s" : ""}`}
370→                    color="text-violet-400"
371→                    tooltip="Sub-agent tasks spawned during this session"
372→                  />
373→                )}
374→                {main.project_path && (
375→                  <MetaPill
376→                    icon={<FolderOpen className="w-3 h-3" />}
377→                    label={baseProjectName(main.project_path)}
378→                    color="text-zinc-200"
379→                    tooltip={main.project_path}
380→                  />
381→                )}
382→              </div>
383→            </div>
384→            <div className="flex gap-1 shrink-0 ml-3">
385→              {!isSharedView && (
386→                <button
387→                  onClick={handleShare}
388→                  disabled={shareStatus === "sharing"}
389→                  className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs disabled:opacity-50"
390→                  title={shareStatus === "copied" ? "Link copied!" : "Share session"}
391→                >
392→                  {shareStatus === "copied" ? (
393→                    <Check className="w-4 h-4 text-emerald-400" />
394→                  ) : shareStatus === "sharing" ? (
395→                    <Loader2 className="w-4 h-4 animate-spin" />
396→                  ) : (
397→                    <Share2 className="w-4 h-4" />
398→                  )}
399→                </button>
400→              )}
401→              <button
402→                onClick={() => {
403→                  const link = document.createElement("a");
404→                  link.href = `/api/sessions/${sessionId}/export`;
405→                  link.download = `vibelens-${sessionId.slice(0, 8)}.json`;
406→                  document.body.appendChild(link);
407→                  link.click();
408→                  document.body.removeChild(link);
409→                }}
410→                className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs"
411→                title="Download session"
412→              >
413→                <Download className="w-4 h-4" />
414→              </button>
415→            </div>
416→          </div>
417→
418→          {/* Row 2: Token Stats */}
419→          {metrics && (metrics.total_prompt_tokens != null || metrics.total_completion_tokens != null) && (
420→            <div className={`grid ${sessionCost != null ? "grid-cols-6" : "grid-cols-5"} gap-2 text-xs`}>
421→              <TokenStat label="Input" value={metrics.total_prompt_tokens || 0} color="text-cyan-300" tooltip="Prompt tokens sent to the model" />
422→              <TokenStat label="Output" value={metrics.total_completion_tokens || 0} color="text-cyan-300" tooltip="Completion tokens generated by the model" />
423→              <TokenStat label="Cache Read" value={metrics.total_cache_read || 0} color="text-green-300" tooltip="Tokens served from prompt cache (reduced cost)" />
424→              <TokenStat label="Cache Write" value={metrics.total_cache_write || 0} color="text-violet-300" tooltip="Tokens written to prompt cache for future reuse" />
425→              <TokenStat label="Total" value={totalTokens} color="text-amber-300" tooltip="Total tokens (input + output)" />
426→              {sessionCost != null && (
427→                <CostStat value={sessionCost} />
428→              )}
429→            </div>
430→          )}
431→        </div>
432→      </div>
433→
434→      {/* Two-column body: Steps + Prompt Nav */}
435→      <div className="flex-1 flex min-h-0">
