442→                <p>No steps to display</p>
443→              </div>
444→            ) : (
445→              <>
446→                <StepTimeline
447→                  entries={steps
448→                    .filter((step) => {
449→                      const visible = isVisibleStep(step);
450→                      const spawnedSubs = subAgentsByStep.map.get(step.step_id);
451→                      return visible || !!spawnedSubs;
452→                    })
453→                    .map((step) => {
454→                      const visible = isVisibleStep(step);
455→                      const spawnedSubs = subAgentsByStep.map.get(step.step_id);
456→                      return {
457→                        step,
458→                        content: (
459→                          <div id={`step-${step.step_id}`} style={{ scrollMarginTop: "1rem" }}>
460→                            {visible && <StepBlock step={step} />}
461→                            {spawnedSubs?.map((sub) => (
462→                              <div key={sub.session_id} id={`subagent-${sub.session_id}`} className="mt-2">
463→                                <SubAgentBlock
464→                                  trajectory={sub}
465→                                  allTrajectories={trajectories}
466→                                />
467→                              </div>
468→                            ))}
469→                          </div>
470→                        ),
471→                      };
472→                    })}
473→                  sessionStartMs={
474→                    main.timestamp
475→                      ? new Date(main.timestamp).getTime()
476→                      : null
477→                  }
478→                  sessionStartTimestamp={main.timestamp}
479→                />
480→                {subAgentsByStep.orphans.map((sub) => (
481→                  <div key={sub.session_id} id={`subagent-${sub.session_id}`}>
482→                    <SubAgentBlock
483→                      trajectory={sub}
484→                      allTrajectories={trajectories}
485→                    />
486→                  </div>
487→                ))}
488→              </>
489→            )}
490→          </div>
491→        </div>
492→
493→        {/* Prompt Navigation Sidebar */}
494→        <PromptNavPanel
495→          steps={steps}
496→          subAgents={subAgents}
497→          activeStepId={activeStepId}
498→          onNavigate={handlePromptNavigate}
499→          width={promptNavWidth}
500→          onResize={handlePromptNavResize}
501→        />
502→      </div>
503→    </div>
504→  );
505→}
506→
507→function MetaPill({
508→  icon,
509→  label,
510→  color,
511→  tooltip,
512→}: {
513→  icon: React.ReactNode;
514→  label: string;
515→  color: string;
516→  tooltip?: string;
517→}) {
518→  const [show, setShow] = useState(false);
519→  const ref = useRef<HTMLSpanElement>(null);
520→
521→  return (
522→    <span
523→      ref={ref}
524→      className={`relative inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-zinc-800 border border-zinc-700/50 text-[11px] ${color}`}
525→      onMouseEnter={() => setShow(true)}
526→      onMouseLeave={() => setShow(false)}
527→    >
528→      {icon}
529→      <span>{label}</span>
530→      {tooltip && show && (
531→        <span className="absolute left-0 top-full mt-1.5 z-[100] px-2.5 py-1.5 rounded-md bg-zinc-950 border border-zinc-700 text-[11px] text-zinc-300 whitespace-nowrap shadow-lg pointer-events-none">
532→          {tooltip}
533→        </span>
534→      )}
